public static long[] solve(long[] nums, long[][] queries) {
    int n = nums.length;
    int m = queries.length;
    long[] ans = new long[m];

    for (int i = 0; i < m; i++) {
        long l = queries[i][0];
        long r = queries[i][1];
        long threshold = queries[i][2];
        java.util.Map<Long, Integer> freq = new java.util.HashMap<>();
        for (int j = (int) l; j <= (int) r; j++) {
            freq.put(nums[j], freq.getOrDefault(nums[j], 0) + 1);
        }
        long res = -1;
        for (java.util.Map.Entry<Long, Integer> entry : freq.entrySet()) {
            if (entry.getValue() >= threshold) {
                if (res == -1 || entry.getValue() > freq.get(res) || (entry.getValue() == freq.get(res) && entry.getKey() < res)) {
                    res = entry.getKey();
                }
            }
        }
        ans[i] = res;
    }
    return ans;
}
