#include <vector>
#include <map>
#include <algorithm>

using namespace std;

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    vector<long long> ans;
    int n = nums.size();
    // Preprocess for each position, store the frequency of elements
    // Using a 2D array to store frequency of elements from index i to j
    // But since n can be up to 1e4, a 2D array would be too large (1e8 elements)
    // So we use a different approach for each query

    for (auto& query : queries) {
        long long l = query[0], r = query[1], threshold = query[2];
        map<long long, int> freq;
        for (int i = l; i <= r; ++i) {
            freq[nums[i]]++;
        }
        long long res = -1;
        for (auto& [num, count] : freq) {
            if (count >= threshold) {
                if (res == -1 || count > freq[res] || (count == freq[res] && num < res)) {
                    res = num;
                }
            }
        }
        ans.push_back(res);
    }
    return ans;
}
